-- ===================================================================
-- COURSE: Concept Dictionary Management
-- ===================================================================
VALUES (UUID(), 25, 1, TRUE, 1, NOW(), FALSE);
SET @course_id = LAST_INSERT_ID();



-- ===================================================================
-- LESSON 1: Getting Started with Concepts
-- ===================================================================
VALUES (UUID(), '[{"type":"heading","content":{"en":"Getting Started with Concepts","fr":"Débuter avec les concepts"},"properties":{"level":1}},{"type":"paragraph","content":{"en":"The Concept Dictionary is central to OpenMRS. It serves as the central repository for all medical and administrative terminology used throughout the system. Every piece of clinical data captured in OpenMRS - from vital signs to diagnoses - is represented by a concept. Understanding how to create and manage concepts is essential for building effective forms and ensuring data quality.","fr":"Le dictionnaire de concepts est central dans OpenMRS. Il sert de référentiel central pour toute la terminologie médicale et administrative utilisée dans le système. Chaque donnée clinique capturée dans OpenMRS - des signes vitaux aux diagnostics - est représentée par un concept. Comprendre comment créer et gérer des concepts est essentiel pour construire des formulaires efficaces et assurer la qualité des données."}},{"type":"heading","content":{"en":"Why the Concept Dictionary Matters","fr":"Pourquoi le dictionnaire de concepts est important"},"properties":{"level":2}},{"type":"list","items":[{"en":"Data Standardization: Ensures all users record information consistently using the same terminology","fr":"Standardisation des données : Assure que tous les utilisateurs enregistrent les informations de manière cohérente en utilisant la même terminologie"},{"en":"Form Building: Concepts are the building blocks for creating data collection forms","fr":"Construction de formulaires : Les concepts sont les éléments de base pour créer des formulaires de collecte de données"},{"en":"Reporting and Analytics: Standardized concepts enable accurate data analysis and report generation","fr":"Rapports et analyses : Les concepts standardisés permettent une analyse précise des données et la génération de rapports"},{"en":"Interoperability: Mapped concepts allow data exchange with external systems and databases","fr":"Interopérabilité : Les concepts mappés permettent l''échange de données avec des systèmes et bases de données externes"}],"properties":{"ordered":false}},{"type":"heading","content":{"en":"Creating Your First Concept","fr":"Créer votre premier concept"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"To create a concept, navigate to System Administration → Legacy Admin → Manage Concepts. Click Add Concept to open the creation form. Every concept requires four essential components:","fr":"Pour créer un concept, naviguez vers Administration système → Administration héritée → Gérer les concepts. Cliquez sur Ajouter un concept pour ouvrir le formulaire de création. Chaque concept nécessite quatre composants essentiels :"}},{"type":"list","items":[{"en":"Names: At least one fully specified name that precisely describes the concept, plus optional synonyms and short names for common usage","fr":"Noms : Au moins un nom entièrement spécifié qui décrit précisément le concept, plus des synonymes optionnels et des noms courts pour l''usage courant"},{"en":"Description: A clear explanation of what the concept represents and when it should be used","fr":"Description : Une explication claire de ce que le concept représente et quand il doit être utilisé"},{"en":"Class: Categorizes the concept (Finding, Diagnosis, Test, Drug, etc.) to organize the dictionary","fr":"Classe : Catégorise le concept (Constat, Diagnostic, Test, Médicament, etc.) pour organiser le dictionnaire"},{"en":"Datatype: Defines what type of values the concept can accept (Numeric, Coded, Text, Boolean, etc.)","fr":"Type de données : Définit le type de valeurs que le concept peut accepter (Numérique, Codé, Texte, Booléen, etc.)"}],"properties":{"ordered":true}},{"type":"heading","content":{"en":"Concept Classes and Datatypes","fr":"Classes et types de données de concept"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"The concept class helps organize your dictionary. Common classes include Finding (observable clinical facts), Diagnosis (medical conditions), Test (laboratory or diagnostic procedures), Drug (medications), and Question (items that prompt for answers). The datatype determines how data is stored and validated. Numeric is used for measurements with units, Coded for multiple choice questions, Text for free-text entries, Boolean for yes/no questions, and N/A for concepts that don''t store values directly (like concept sets).","fr":"La classe de concept aide à organiser votre dictionnaire. Les classes courantes incluent Constat (faits cliniques observables), Diagnostic (conditions médicales), Test (procédures de laboratoire ou diagnostiques), Médicament (médicaments) et Question (éléments qui demandent des réponses). Le type de données détermine comment les données sont stockées et validées. Numérique est utilisé pour les mesures avec unités, Codé pour les questions à choix multiples, Texte pour les entrées en texte libre, Booléen pour les questions oui/non, et N/A pour les concepts qui ne stockent pas directement de valeurs (comme les ensembles de concepts)."}},{"type":"alert","content":{"en":"Critical Safety Rule: Once a concept is in use by forms and contains patient data, never delete it. Instead, use the Retire function. Retiring a concept preserves historical data while preventing future use. Deleting a concept can corrupt your database and violate data integrity.","fr":"Règle de sécurité critique : Une fois qu''un concept est utilisé par des formulaires et contient des données de patients, ne le supprimez jamais. Utilisez plutôt la fonction Retirer. Retirer un concept préserve les données historiques tout en empêchant une utilisation future. Supprimer un concept peut corrompre votre base de données et violer l''intégrité des données."},"properties":{"variant":"warning"}},{"type":"alert","content":{"en":"Critical Constraint: Once a concept has been used to collect patient data, its datatype cannot be changed. Changing a datatype would corrupt existing observations and violate data integrity. If you need a different datatype, you must create a new concept with the correct datatype and retire the old one. This is another reason to plan your concepts carefully before deploying forms.","fr":"Contrainte critique : Une fois qu''un concept a été utilisé pour collecter des données de patients, son type de données ne peut pas être modifié. Changer un type de données corromprait les observations existantes et violerait l''intégrité des données. Si vous avez besoin d''un type de données différent, vous devez créer un nouveau concept avec le type de données correct et retirer l''ancien. C''est une autre raison de planifier soigneusement vos concepts avant de déployer des formulaires."},"properties":{"variant":"warning"}},{"type":"heading","content":{"en":"Best Practices for Concept Names","fr":"Meilleures pratiques pour les noms de concept"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Use clear, unambiguous fully specified names that include context. For example, use \\"Weight (kg)\\" instead of just \\"Weight\\" to clarify the unit of measurement. Add synonyms for common variations healthcare workers might use. Short names are useful for display in constrained spaces like mobile interfaces. Always provide names in the primary language of your implementation, and add translations for multilingual environments.","fr":"Utilisez des noms entièrement spécifiés clairs et non ambigus qui incluent le contexte. Par exemple, utilisez \\"Poids (kg)\\" au lieu de simplement \\"Poids\\" pour clarifier l''unité de mesure. Ajoutez des synonymes pour les variations courantes que les professionnels de santé pourraient utiliser. Les noms courts sont utiles pour l''affichage dans des espaces contraints comme les interfaces mobiles. Fournissez toujours des noms dans la langue principale de votre implémentation et ajoutez des traductions pour les environnements multilingues."}}]', 2, 1, NOW(), FALSE);
SET @lesson_id_1 = LAST_INSERT_ID();



-- ===================================================================
-- EXERCISE 1: Concept Retirement Best Practice (True/False)
-- ===================================================================
VALUES (UUID(), 'TRUE_FALSE', '{"statement":{"en":"If you discover an error in a concept that is already being used in forms with patient data, you should delete the concept and create a new corrected version.","fr":"Si vous découvrez une erreur dans un concept déjà utilisé dans des formulaires avec des données de patients, vous devez supprimer le concept et créer une nouvelle version corrigée."}}', '{"correctAnswer":"false"}', '{"correct":{"en":"Correct! Never delete concepts that are in use. Deleting a concept that has associated patient data can corrupt your database and violate data integrity. Instead, retire the incorrect concept (which preserves all historical data) and create a new corrected concept for future use. You can add a retire reason explaining the issue, which helps other administrators understand why the concept was retired.","fr":"Correct ! Ne supprimez jamais les concepts en cours d''utilisation. Supprimer un concept qui a des données de patients associées peut corrompre votre base de données et violer l''intégrité des données. Au lieu de cela, retirez le concept incorrect (ce qui préserve toutes les données historiques) et créez un nouveau concept corrigé pour une utilisation future. Vous pouvez ajouter une raison de retrait expliquant le problème, ce qui aide les autres administrateurs à comprendre pourquoi le concept a été retiré."},"incorrect":{"en":"Incorrect. This is a critical safety rule. Never delete concepts that contain patient data. Review the Critical Safety Rule in the lesson: Always use Retire instead of Delete. Retiring preserves historical data integrity while preventing future use of the problematic concept. This ensures your database remains consistent and patient records remain valid.","fr":"Incorrect. C''est une règle de sécurité critique. Ne supprimez jamais les concepts qui contiennent des données de patients. Révisez la Règle de sécurité critique dans la leçon : Utilisez toujours Retirer au lieu de Supprimer. Retirer préserve l''intégrité des données historiques tout en empêchant l''utilisation future du concept problématique. Cela garantit que votre base de données reste cohérente et que les dossiers des patients restent valides."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_1 = LAST_INSERT_ID();


-- ===================================================================
-- EXERCISE 2: Matching - Concept Class Identification
-- ===================================================================
VALUES (UUID(), 'MATCHING', '{"instructions":{"en":"Match each concept example with its correct concept class.","fr":"Associez chaque exemple de concept à sa classe de concept correcte."},"leftItems":[{"id":"1","text":{"en":"Weight (kg)","fr":"Poids (kg)"}},{"id":"2","text":{"en":"Tuberculosis","fr":"Tuberculose"}},{"id":"3","text":{"en":"Appendectomy","fr":"Appendicectomie"}},{"id":"4","text":{"en":"Have you experienced fever in the last 7 days?","fr":"Avez-vous eu de la fièvre au cours des 7 derniers jours ?"}},{"id":"5","text":{"en":"Hemoglobin Test","fr":"Test d''hémoglobine"}}],"rightItems":[{"id":"a","text":{"en":"Question","fr":"Question"}},{"id":"b","text":{"en":"Finding","fr":"Constat"}},{"id":"c","text":{"en":"Diagnosis","fr":"Diagnostic"}},{"id":"d","text":{"en":"Procedure","fr":"Procédure"}},{"id":"e","text":{"en":"Test","fr":"Test"}}]}', '{"correctMatches":{"1":"b","2":"c","3":"d","4":"a","5":"e"}}', '{"correct":{"en":"Excellent! You correctly matched all concept examples to their classes. Weight is a Finding, Tuberculosis is a Diagnosis, Appendectomy is a Procedure, fever questions are Questions, and Hemoglobin Test is a Test.","fr":"Excellent ! Vous avez correctement associé tous les exemples de concepts à leurs classes. Poids est un Constat, Tuberculose est un Diagnostic, Appendicectomie est une Procédure, les questions sur la fièvre sont des Questions, et Test d''hémoglobine est un Test."},"incorrect":{"en":"Review the concept classes section in the lesson. Think about what each concept represents: observations (Finding), conditions (Diagnosis), interventions (Procedure), data collection (Question), or examinations (Test).","fr":"Révisez la section des classes de concepts dans la leçon. Pensez à ce que représente chaque concept : observations (Constat), conditions (Diagnostic), interventions (Procédure), collecte de données (Question), ou examens (Test)."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_2 = LAST_INSERT_ID();


-- ===================================================================
-- EXERCISE 3: True/False - Datatype Modification Rules
-- ===================================================================
VALUES (UUID(), 'TRUE_FALSE', '{"statement":{"en":"After a concept has been used to collect patient data, you can change its datatype if you realize you made a mistake.","fr":"Après qu''un concept a été utilisé pour collecter des données de patients, vous pouvez changer son type de données si vous réalisez avoir fait une erreur."}}', '{"correctAnswer":"false"}', '{"correct":{"en":"Correct! Once a concept has been used to collect data, its datatype cannot be changed. This restriction protects data integrity. If you need a different datatype, you must create a new concept.","fr":"Correct ! Une fois qu''un concept a été utilisé pour collecter des données, son type de données ne peut pas être modifié. Cette restriction protège l''intégrité des données. Si vous avez besoin d''un type de données différent, vous devez créer un nouveau concept."},"incorrect":{"en":"Incorrect. Changing a concept''s datatype after data collection would corrupt existing data. OpenMRS prevents this to maintain data integrity. You must create a new concept if you need a different datatype.","fr":"Incorrect. Changer le type de données d''un concept après la collecte de données corromprait les données existantes. OpenMRS empêche cela pour maintenir l''intégrité des données. Vous devez créer un nouveau concept si vous avez besoin d''un type de données différent."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_3 = LAST_INSERT_ID();


-- ===================================================================
-- LESSON 2: Numeric Concepts
-- ===================================================================
VALUES (UUID(), '[{"type":"heading","content":{"en":"Numeric Concepts","fr":"Concepts numériques"},"properties":{"level":1}},{"type":"paragraph","content":{"en":"Numeric concepts are used for measurements and quantitative data like vital signs, lab results, and physical measurements. They require special configuration to ensure data quality and provide meaningful validation.","fr":"Les concepts numériques sont utilisés pour les mesures et les données quantitatives comme les signes vitaux, les résultats de laboratoire et les mesures physiques. Ils nécessitent une configuration spéciale pour garantir la qualité des données et fournir une validation significative."}},{"type":"heading","content":{"en":"Essential Numeric Properties","fr":"Propriétés numériques essentielles"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"When creating a numeric concept, you must specify the unit of measurement (kg, cm, °C, mmHg, etc.). This is not just documentation - it tells clinicians what unit to enter values in and helps ensure consistency. You should also define whether the concept allows decimal values. For example, weight typically allows decimals (72.5 kg), while counts do not (3 children). The display precision determines how many decimal places are shown in reports and forms.","fr":"Lors de la création d''un concept numérique, vous devez spécifier l''unité de mesure (kg, cm, °C, mmHg, etc.). Ce n''est pas seulement de la documentation - cela indique aux cliniciens dans quelle unité entrer les valeurs et aide à garantir la cohérence. Vous devez également définir si le concept permet des valeurs décimales. Par exemple, le poids permet généralement les décimales (72,5 kg), tandis que les comptages ne le permettent pas (3 enfants). La précision d''affichage détermine combien de décimales sont affichées dans les rapports et les formulaires."}},{"type":"heading","content":{"en":"Understanding Ranges","fr":"Comprendre les plages"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Numeric concepts support three types of ranges that provide increasingly strict validation:","fr":"Les concepts numériques prennent en charge trois types de plages qui fournissent une validation de plus en plus stricte :"}},{"type":"list","items":[{"en":"Absolute Range (Hi/Low Absolute): The physically possible limits. Values outside this range are biologically impossible. Example: Body temperature cannot be below 25°C or above 45°C for a living patient.","fr":"Plage absolue (Haut/Bas absolu) : Les limites physiquement possibles. Les valeurs en dehors de cette plage sont biologiquement impossibles. Exemple : La température corporelle ne peut pas être inférieure à 25°C ou supérieure à 45°C pour un patient vivant."},{"en":"Critical Range (Hi/Low Critical): Values that indicate a medical emergency requiring immediate attention. Example: Body temperature above 40°C or below 35°C requires urgent intervention.","fr":"Plage critique (Haut/Bas critique) : Valeurs qui indiquent une urgence médicale nécessitant une attention immédiate. Exemple : Une température corporelle supérieure à 40°C ou inférieure à 35°C nécessite une intervention urgente."},{"en":"Normal Range (Hi/Low Normal): The expected healthy range. Values outside are abnormal but not necessarily critical. Example: Normal body temperature is 36.5-37.5°C.","fr":"Plage normale (Haut/Bas normal) : La plage saine attendue. Les valeurs en dehors sont anormales mais pas nécessairement critiques. Exemple : La température corporelle normale est de 36,5-37,5°C."}],"properties":{"ordered":true}},{"type":"paragraph","content":{"en":"These ranges work together to validate data entry. The system can warn users when values fall outside the normal range (suggesting double-checking), alert for critical values (requiring confirmation), and reject absolutely impossible values. This progressive validation helps catch data entry errors while allowing legitimate abnormal values.","fr":"Ces plages fonctionnent ensemble pour valider la saisie des données. Le système peut avertir les utilisateurs lorsque les valeurs sortent de la plage normale (suggérant une vérification), alerter pour les valeurs critiques (nécessitant une confirmation) et rejeter les valeurs absolument impossibles. Cette validation progressive aide à détecter les erreurs de saisie de données tout en permettant des valeurs anormales légitimes."}},{"type":"alert","content":{"en":"Best Practice: Always set absolute ranges to prevent impossible values. Set normal ranges for common measurements to help catch data entry errors. Critical ranges are optional but valuable for clinical decision support.","fr":"Meilleure pratique : Définissez toujours des plages absolues pour empêcher les valeurs impossibles. Définissez des plages normales pour les mesures courantes afin d''aider à détecter les erreurs de saisie de données. Les plages critiques sont optionnelles mais précieuses pour l''aide à la décision clinique."},"properties":{"variant":"info"}}]', 2, 1, NOW(), FALSE);
SET @lesson_id_2 = LAST_INSERT_ID();



-- ===================================================================
-- EXERCISE 4: Create Weight Concept (CONCEPT_CREATION)
-- ===================================================================
VALUES (UUID(), 'CONCEPT_CREATION', '{"instructions":{"en":"Create a numeric concept for recording patient weight in kilograms. This is a fundamental vital sign that will be used in many forms.","fr":"Créez un concept numérique pour enregistrer le poids des patients en kilogrammes. C''est un signe vital fondamental qui sera utilisé dans de nombreux formulaires."},"requirements":{"name":{"primary":{"en":"Weight (kg)","fr":"Poids (kg)"},"synonyms":[{"en":"Weight","fr":"Poids"},{"en":"Body Weight","fr":"Poids corporel"}],"shortName":{"en":"Wt","fr":"Pds"}},"description":{"en":"Patient body weight measured in kilograms. Used to track growth, calculate medication dosages, and monitor health status.","fr":"Poids corporel du patient mesuré en kilogrammes. Utilisé pour suivre la croissance, calculer les dosages de médicaments et surveiller l''état de santé."},"class":"Finding","datatype":"Numeric","numericProperties":{"units":"kg","allowDecimal":true,"displayPrecision":1,"hiAbsolute":250,"lowAbsolute":0.5,"hiNormal":100,"lowNormal":40}}}', '{}', '{"correct":{"en":"Excellent! You have created a properly configured weight concept. Notice how the absolute range (0.5-250 kg) prevents impossible values, while the normal range (40-100 kg) helps identify values that might need verification. The unit specification (kg) ensures consistent data entry, and allowing decimals with one decimal place precision provides appropriate accuracy for this measurement.","fr":"Excellent ! Vous avez créé un concept de poids correctement configuré. Remarquez comment la plage absolue (0,5-250 kg) empêche les valeurs impossibles, tandis que la plage normale (40-100 kg) aide à identifier les valeurs qui pourraient nécessiter une vérification. La spécification de l''unité (kg) garantit une saisie de données cohérente, et permettre les décimales avec une précision d''une décimale fournit une précision appropriée pour cette mesure."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_4 = LAST_INSERT_ID();


-- ===================================================================
-- LESSON 3: Coded Concepts & Concept Sets
-- ===================================================================
VALUES (UUID(), '[{"type":"heading","content":{"en":"Coded Concepts & Concept Sets","fr":"Concepts codés et ensembles de concepts"},"properties":{"level":1}},{"type":"paragraph","content":{"en":"Coded concepts enable multiple choice questions where users select from predefined options. Concept sets group related concepts together to organize complex data. Both are essential tools for building structured, user-friendly forms.","fr":"Les concepts codés permettent des questions à choix multiples où les utilisateurs sélectionnent parmi des options prédéfinies. Les ensembles de concepts regroupent des concepts connexes pour organiser des données complexes. Les deux sont des outils essentiels pour construire des formulaires structurés et conviviaux."}},{"type":"heading","content":{"en":"Creating Coded Concepts","fr":"Créer des concepts codés"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"A coded concept has two components: the question concept itself and its answer concepts. First, create the question concept with datatype Coded. Then, define the possible answers by adding answer concepts to its answer set. Each answer is itself a concept from your dictionary. For example, to create a Blood Type concept, you would create one coded concept for the question, then add concepts like \\"A Positive\\", \\"B Negative\\", \\"O Positive\\", and \\"AB Negative\\" as the possible answers.","fr":"Un concept codé a deux composants : le concept de question lui-même et ses concepts de réponse. Tout d''abord, créez le concept de question avec le type de données Codé. Ensuite, définissez les réponses possibles en ajoutant des concepts de réponse à son ensemble de réponses. Chaque réponse est elle-même un concept de votre dictionnaire. Par exemple, pour créer un concept de Groupe sanguin, vous créeriez un concept codé pour la question, puis ajouteriez des concepts comme \\"A Positif\\", \\"B Négatif\\", \\"O Positif\\" et \\"AB Négatif\\" comme réponses possibles."}},{"type":"paragraph","content":{"en":"The answers must exist as concepts before you can add them to the coded concept. This two-step process gives you flexibility - the same answer concepts can be reused in multiple questions. For instance, a \\"Yes\\" concept can be an answer to many different yes/no questions.","fr":"Les réponses doivent exister en tant que concepts avant de pouvoir les ajouter au concept codé. Ce processus en deux étapes vous donne de la flexibilité - les mêmes concepts de réponse peuvent être réutilisés dans plusieurs questions. Par exemple, un concept \\"Oui\\" peut être une réponse à de nombreuses questions oui/non différentes."}},{"type":"heading","content":{"en":"Working with Concept Sets","fr":"Travailler avec des ensembles de concepts"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Concept sets group related concepts into a single parent concept. This is particularly useful for complex measurements that have multiple components. A classic example is Blood Pressure, which consists of two separate numeric measurements: Systolic and Diastolic pressure. Rather than recording these as independent observations, you create a Blood Pressure concept set that contains both measurements.","fr":"Les ensembles de concepts regroupent des concepts connexes dans un seul concept parent. C''est particulièrement utile pour les mesures complexes qui ont plusieurs composants. Un exemple classique est la Pression artérielle, qui se compose de deux mesures numériques distinctes : pression Systolique et Diastolique. Plutôt que d''enregistrer celles-ci comme des observations indépendantes, vous créez un ensemble de concepts de Pression artérielle qui contient les deux mesures."}},{"type":"paragraph","content":{"en":"To create a concept set, make a concept with datatype N/A and mark it as a set. Then add the member concepts that belong to the set. Concept sets help organize related measurements and improve reporting by keeping related data logically grouped.","fr":"Pour créer un ensemble de concepts, créez un concept avec le type de données N/A et marquez-le comme un ensemble. Ensuite, ajoutez les concepts membres qui appartiennent à l''ensemble. Les ensembles de concepts aident à organiser les mesures connexes et améliorent les rapports en gardant les données connexes logiquement regroupées."}},{"type":"heading","content":{"en":"Best Practices","fr":"Meilleures pratiques"},"properties":{"level":2}},{"type":"list","items":[{"en":"For coded concepts, create clear, mutually exclusive answer options. Avoid overlapping choices that could confuse users.","fr":"Pour les concepts codés, créez des options de réponse claires et mutuellement exclusives. Évitez les choix qui se chevauchent et qui pourraient confondre les utilisateurs."},{"en":"Use concept sets for measurements that are always collected together and are clinically meaningless when separated.","fr":"Utilisez des ensembles de concepts pour les mesures qui sont toujours collectées ensemble et qui sont cliniquement insignifiantes lorsqu''elles sont séparées."},{"en":"Keep answer lists reasonably short (under 10 options when possible). Long lists are difficult for users and may indicate the need for a different question structure.","fr":"Gardez les listes de réponses raisonnablement courtes (moins de 10 options si possible). Les longues listes sont difficiles pour les utilisateurs et peuvent indiquer la nécessité d''une structure de question différente."},{"en":"Standardize common answer sets (Yes/No, Male/Female, etc.) across your dictionary to maintain consistency.","fr":"Standardisez les ensembles de réponses courants (Oui/Non, Homme/Femme, etc.) dans votre dictionnaire pour maintenir la cohérence."}],"properties":{"ordered":false}},{"type":"alert","content":{"en":"Important: The order of answers in a coded concept affects how they display in forms. Arrange answers in a logical order (alphabetical, severity-based, or frequency-based) to make forms easier to use.","fr":"Important : L''ordre des réponses dans un concept codé affecte la façon dont elles s''affichent dans les formulaires. Organisez les réponses dans un ordre logique (alphabétique, basé sur la gravité ou la fréquence) pour faciliter l''utilisation des formulaires."},"properties":{"variant":"info"}}]', 2, 1, NOW(), FALSE);
SET @lesson_id_3 = LAST_INSERT_ID();



-- ===================================================================
-- EXERCISE 5: Create Blood Type Coded Concept (CONCEPT_CREATION)
-- ===================================================================
VALUES (UUID(), 'CONCEPT_CREATION', '{"instructions":{"en":"Create a coded concept for Blood Type with all major blood groups as answer options. This demonstrates creating a multiple choice question.","fr":"Créez un concept codé pour le Groupe sanguin avec tous les groupes sanguins majeurs comme options de réponse. Cela démontre la création d''une question à choix multiples."},"requirements":{"name":{"primary":{"en":"Blood Type","fr":"Groupe sanguin"},"synonyms":[{"en":"Blood Group","fr":"Groupe sanguin"},{"en":"ABO Blood Type","fr":"Type sanguin ABO"}]},"description":{"en":"Patient ABO and Rh blood type classification. Essential for blood transfusions and medical procedures.","fr":"Classification du groupe sanguin ABO et Rh du patient. Essentiel pour les transfusions sanguines et les procédures médicales."},"class":"Finding","datatype":"Coded","codedProperties":[{"conceptName":{"en":"A positive","fr":"A positif"}},{"conceptName":{"en":"A negative","fr":"A négatif"}},{"conceptName":{"en":"B positive","fr":"B positif"}},{"conceptName":{"en":"B negative","fr":"B négatif"}},{"conceptName":{"en":"O positive","fr":"O positif"}},{"conceptName":{"en":"O negative","fr":"O négatif"}},{"conceptName":{"en":"AB positive","fr":"AB positif"}},{"conceptName":{"en":"AB negative","fr":"AB négatif"}}]}}', '{}', '{"correct":{"en":"Excellent! You have created a proper coded concept with a complete set of mutually exclusive answers. Notice how each answer is itself a concept that can be reused. The eight options cover all standard blood types, and the logical ordering makes the form easy to use. Coded concepts like this ensure data consistency - everyone records blood type using the same standardized options rather than free text that could vary.","fr":"Excellent ! Vous avez créé un concept codé approprié avec un ensemble complet de réponses mutuellement exclusives. Remarquez comment chaque réponse est elle-même un concept qui peut être réutilisé. Les huit options couvrent tous les groupes sanguins standard, et l''ordre logique rend le formulaire facile à utiliser. Les concepts codés comme celui-ci garantissent la cohérence des données - tout le monde enregistre le groupe sanguin en utilisant les mêmes options standardisées plutôt que du texte libre qui pourrait varier."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_5 = LAST_INSERT_ID();


-- ===================================================================
-- EXERCISE 6: Create Blood Pressure Concept Set (CONCEPT_CREATION)
-- ===================================================================
VALUES (UUID(), 'CONCEPT_CREATION', '{"instructions":{"en":"Create a Blood Pressure concept set containing Systolic and Diastolic pressure measurements. This demonstrates grouping related numeric concepts.","fr":"Créez un ensemble de concepts de Pression artérielle contenant les mesures de pression Systolique et Diastolique. Cela démontre le regroupement de concepts numériques connexes."},"requirements":{"name":{"primary":{"en":"Blood Pressure","fr":"Pression artérielle"},"synonyms":[{"en":"BP","fr":"TA"}],"shortName":{"en":"BP","fr":"TA"}},"description":{"en":"Blood pressure measurement consisting of systolic and diastolic values in mmHg. Critical vital sign for cardiovascular health assessment.","fr":"Mesure de la pression artérielle composée de valeurs systolique et diastolique en mmHg. Signe vital critique pour l''évaluation de la santé cardiovasculaire."},"class":"Finding","datatype":"N/A","isSet":true,"setMembers":[{"conceptName":{"en":"Systolic blood pressure","fr":"Pression artérielle systolique"}},{"conceptName":{"en":"Diastolic blood pressure","fr":"Pression artérielle diastolique"}}]}}', '{}', '{"correct":{"en":"Perfect! You have created a concept set that groups two related measurements. When this concept set is used in a form, both Systolic and Diastolic pressures will be displayed together, making it clear that they are part of a single blood pressure reading. This improves data quality by ensuring both values are captured together and helps with reporting by maintaining the logical relationship between these measurements. Concept sets are essential for complex vital signs and multi-part observations.","fr":"Parfait ! Vous avez créé un ensemble de concepts qui regroupe deux mesures connexes. Lorsque cet ensemble de concepts est utilisé dans un formulaire, les pressions Systolique et Diastolique seront affichées ensemble, indiquant clairement qu''elles font partie d''une seule lecture de pression artérielle. Cela améliore la qualité des données en garantissant que les deux valeurs sont capturées ensemble et aide aux rapports en maintenant la relation logique entre ces mesures. Les ensembles de concepts sont essentiels pour les signes vitaux complexes et les observations en plusieurs parties."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_6 = LAST_INSERT_ID();


-- ===================================================================
-- EXERCISE 7: True/False - Answer Concept Reusability
-- ===================================================================
VALUES (UUID(), 'TRUE_FALSE', '{"statement":{"en":"You should create new answer concepts for each coded question, even if you''re using the same answers (like Yes/No) in multiple questions.","fr":"Vous devriez créer de nouveaux concepts de réponse pour chaque question codée, même si vous utilisez les mêmes réponses (comme Oui/Non) dans plusieurs questions."}}', '{"correctAnswer":"false"}', '{"correct":{"en":"Correct! Answer concepts should be reused across questions. Creating one set of Yes/No concepts and using them in all yes/no questions keeps your dictionary clean and improves data consistency.","fr":"Correct ! Les concepts de réponse doivent être réutilisés entre les questions. Créer un ensemble de concepts Oui/Non et les utiliser dans toutes les questions oui/non garde votre dictionnaire propre et améliore la cohérence des données."},"incorrect":{"en":"Incorrect. Answer concept reusability is a best practice. Common answers like Yes/No, Male/Female should be created once and reused across all applicable questions.","fr":"Incorrect. La réutilisabilité des concepts de réponse est une bonne pratique. Les réponses courantes comme Oui/Non, Masculin/Féminin doivent être créées une fois et réutilisées dans toutes les questions applicables."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_7 = LAST_INSERT_ID();


-- ===================================================================
-- LESSON 4: Mappings & Standards
-- ===================================================================
VALUES (UUID(), '[{"type":"heading","content":{"en":"Mappings & Standards","fr":"Mappages et normes"},"properties":{"level":1}},{"type":"paragraph","content":{"en":"Concept mappings link your OpenMRS concepts to international medical terminology standards like SNOMED CT, LOINC, and ICD-10. These connections enable data exchange with external systems, support interoperability, and allow you to use globally recognized medical terminologies. Understanding how to create and use mappings is essential for implementations that need to share data or comply with national reporting requirements.","fr":"Les mappages de concepts lient vos concepts OpenMRS aux normes de terminologie médicale internationales comme SNOMED CT, LOINC et ICD-10. Ces connexions permettent l''échange de données avec des systèmes externes, soutiennent l''interopérabilité et vous permettent d''utiliser des terminologies médicales reconnues mondialement. Comprendre comment créer et utiliser des mappages est essentiel pour les implémentations qui doivent partager des données ou se conformer aux exigences de reporting nationales."}},{"type":"heading","content":{"en":"Major Mapping Sources","fr":"Principales sources de mappage"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Three international standards are most commonly used for concept mappings:","fr":"Trois normes internationales sont les plus couramment utilisées pour les mappages de concepts :"}},{"type":"list","items":[{"en":"SNOMED CT: Comprehensive clinical terminology covering diseases, findings, procedures, and body structures. The most extensive medical terminology standard worldwide.","fr":"SNOMED CT : Terminologie clinique complète couvrant les maladies, les constatations, les procédures et les structures corporelles. La norme de terminologie médicale la plus étendue au monde."},{"en":"LOINC: Standard for laboratory and clinical observations. Essential for lab results, vital signs, and clinical measurements. If you are mapping lab tests, LOINC is usually the correct choice.","fr":"LOINC : Norme pour les observations de laboratoire et cliniques. Essentiel pour les résultats de laboratoire, les signes vitaux et les mesures cliniques. Si vous mappez des tests de laboratoire, LOINC est généralement le bon choix."},{"en":"ICD-10: International classification of diseases for diagnoses and mortality reporting. Required for health statistics and insurance billing in many countries.","fr":"ICD-10 : Classification internationale des maladies pour les diagnostics et les rapports de mortalité. Requis pour les statistiques de santé et la facturation d''assurance dans de nombreux pays."}],"properties":{"ordered":false}},{"type":"heading","content":{"en":"Creating Concept Mappings","fr":"Créer des mappages de concepts"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"To add a mapping to a concept, you need three pieces of information: the mapping source (SNOMED CT, LOINC, etc.), the code from that source system, and the relationship type. The most common relationship is SAME-AS, indicating that your concept represents exactly the same thing as the code in the external system. Other relationships include NARROWER-THAN (your concept is more specific) and BROADER-THAN (your concept is more general).","fr":"Pour ajouter un mappage à un concept, vous avez besoin de trois informations : la source de mappage (SNOMED CT, LOINC, etc.), le code de ce système source et le type de relation. La relation la plus courante est SAME-AS, indiquant que votre concept représente exactement la même chose que le code dans le système externe. Les autres relations incluent NARROWER-THAN (votre concept est plus spécifique) et BROADER-THAN (votre concept est plus général)."}},{"type":"paragraph","content":{"en":"You can add multiple mappings to a single concept. For example, a Weight concept might map to both a LOINC code (for the observation itself) and a SNOMED CT code (for the clinical finding). This flexibility allows interoperability with different systems that use different standards.","fr":"Vous pouvez ajouter plusieurs mappages à un seul concept. Par exemple, un concept de Poids pourrait mapper à la fois un code LOINC (pour l''observation elle-même) et un code SNOMED CT (pour le constat clinique). Cette flexibilité permet une interopérabilité avec différents systèmes qui utilisent différentes normes."}},{"type":"heading","content":{"en":"Using the CIEL Dictionary","fr":"Utiliser le dictionnaire CIEL"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"The Columbia International eHealth Laboratory (CIEL) maintains a curated dictionary of over 40,000 pre-mapped OpenMRS concepts. These concepts already have mappings to SNOMED CT, LOINC, ICD-10, and other standards. Before creating a new concept, search CIEL to see if a suitable concept already exists. Using CIEL concepts saves time and ensures your concepts have high-quality, vetted mappings.","fr":"Le Columbia International eHealth Laboratory (CIEL) maintient un dictionnaire organisé de plus de 40 000 concepts OpenMRS pré-mappés. Ces concepts ont déjà des mappages vers SNOMED CT, LOINC, ICD-10 et d''autres normes. Avant de créer un nouveau concept, recherchez dans CIEL pour voir si un concept approprié existe déjà. L''utilisation de concepts CIEL fait gagner du temps et garantit que vos concepts ont des mappages de haute qualité et vérifiés."}},{"type":"paragraph","content":{"en":"When you do need to create custom concepts, you can still add mappings to make them interoperable. Search the appropriate standard (SNOMED CT, LOINC, etc.) for the matching code, then add it as a mapping. This combines the flexibility of custom concepts with the interoperability benefits of international standards.","fr":"Lorsque vous devez créer des concepts personnalisés, vous pouvez toujours ajouter des mappages pour les rendre interopérables. Recherchez la norme appropriée (SNOMED CT, LOINC, etc.) pour le code correspondant, puis ajoutez-le en tant que mappage. Cela combine la flexibilité des concepts personnalisés avec les avantages d''interopérabilité des normes internationales."}},{"type":"alert","content":{"en":"Best Practice: Start with CIEL concepts when possible for common clinical terms. For specialized or organization-specific concepts, create custom concepts but add mappings to maintain interoperability. Document your mapping decisions to help future administrators understand the choices made.","fr":"Meilleure pratique : Commencez avec des concepts CIEL lorsque possible pour les termes cliniques courants. Pour les concepts spécialisés ou spécifiques à l''organisation, créez des concepts personnalisés mais ajoutez des mappages pour maintenir l''interopérabilité. Documentez vos décisions de mappage pour aider les futurs administrateurs à comprendre les choix effectués."},"properties":{"variant":"success"}}]', 2, 1, NOW(), FALSE);
SET @lesson_id_4 = LAST_INSERT_ID();



-- ===================================================================
-- EXERCISE 8: Mapping Sources Matching
-- ===================================================================
VALUES (UUID(), 'MATCHING', '{"instructions":{"en":"Match each international standard with its primary use case. Understanding when to use each standard is important for proper concept mapping.","fr":"Associez chaque norme internationale à son cas d''utilisation principal. Comprendre quand utiliser chaque norme est important pour un mappage de concepts approprié."},"leftItems":[{"id":"1","text":{"en":"SNOMED CT","fr":"SNOMED CT"}},{"id":"2","text":{"en":"LOINC","fr":"LOINC"}},{"id":"3","text":{"en":"ICD-10","fr":"ICD-10"}},{"id":"4","text":{"en":"CIEL","fr":"CIEL"}}],"rightItems":[{"id":"a","text":{"en":"Laboratory tests and clinical observations","fr":"Tests de laboratoire et observations cliniques"}},{"id":"b","text":{"en":"Curated OpenMRS dictionary with pre-mapped concepts","fr":"Dictionnaire OpenMRS organisé avec concepts pré-mappés"}},{"id":"c","text":{"en":"Comprehensive clinical terminology for findings and procedures","fr":"Terminologie clinique complète pour les constatations et procédures"}},{"id":"d","text":{"en":"Disease classification for diagnoses and mortality","fr":"Classification des maladies pour diagnostics et mortalité"}}]}', '{"correctMatches":{"1":"c","2":"a","3":"d","4":"b"}}', '{"correct":{"en":"Perfect! You understand when to use each mapping standard. SNOMED CT is the broadest standard, covering most clinical concepts. LOINC specializes in lab tests and observations like vital signs. ICD-10 is specifically for diagnoses and is often required for billing and statistics. CIEL provides ready-to-use OpenMRS concepts that already have mappings to these standards. When creating new concepts, choose the mapping source that best matches your concept type, and consider using CIEL concepts to get high-quality mappings automatically.","fr":"Parfait ! Vous comprenez quand utiliser chaque norme de mappage. SNOMED CT est la norme la plus large, couvrant la plupart des concepts cliniques. LOINC se spécialise dans les tests de laboratoire et les observations comme les signes vitaux. ICD-10 est spécifiquement pour les diagnostics et est souvent requis pour la facturation et les statistiques. CIEL fournit des concepts OpenMRS prêts à l''emploi qui ont déjà des mappages vers ces normes. Lors de la création de nouveaux concepts, choisissez la source de mappage qui correspond le mieux à votre type de concept, et envisagez d''utiliser des concepts CIEL pour obtenir automatiquement des mappages de haute qualité."},"incorrect":{"en":"Review the Major Mapping Sources section. Remember: SNOMED CT (comprehensive clinical terminology), LOINC (labs and observations), ICD-10 (diagnoses), and CIEL (pre-mapped OpenMRS concepts). Think about what type of medical information each standard specializes in.","fr":"Révisez la section Principales sources de mappage. Rappel : SNOMED CT (terminologie clinique complète), LOINC (laboratoires et observations), ICD-10 (diagnostics), et CIEL (concepts OpenMRS pré-mappés). Pensez au type d''information médicale dans lequel chaque norme se spécialise."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_8 = LAST_INSERT_ID();


-- ===================================================================
-- EXERCISE 9: Using CIEL Concept (CONCEPT_CREATION)
-- ===================================================================
VALUES (UUID(), 'CONCEPT_CREATION', '{"instructions":{"en":"Import or reference the CIEL concept for Hemoglobin measurement. This demonstrates using pre-mapped concepts from CIEL instead of creating everything from scratch.","fr":"Importez ou référencez le concept CIEL pour la mesure d''Hémoglobine. Cela démontre l''utilisation de concepts pré-mappés de CIEL au lieu de tout créer à partir de zéro."},"requirements":{"name":{"primary":{"en":"Hemoglobin","fr":"Hémoglobine"},"synonyms":[{"en":"Hb","fr":"Hb"},{"en":"Haemoglobin","fr":"Hémoglobine"}]},"description":{"en":"Concentration of hemoglobin in blood, measured in g/dL. Critical lab value for assessing anemia and oxygen-carrying capacity.","fr":"Concentration d''hémoglobine dans le sang, mesurée en g/dL. Valeur de laboratoire critique pour évaluer l''anémie et la capacité de transport d''oxygène."},"class":"Test","datatype":"Numeric","numericProperties":{"units":"g/dL","allowDecimal":true,"displayPrecision":1,"hiAbsolute":25,"lowAbsolute":2,"hiNormal":17,"lowNormal":12},"mappings":[{"relationship":"SAME-AS","source":"LOINC","code":"718-7"},{"relationship":"SAME-AS","source":"CIEL","code":"21"}]}}', '{}', '{"correct":{"en":"Excellent! You have successfully used a CIEL concept. Notice that this concept comes with multiple mappings already configured - both LOINC (718-7) for lab interoperability and the CIEL identifier (21). By using CIEL concepts for common clinical terms, you save time on mapping research and benefit from the community''s expertise. The CIEL team has already done the work of finding the correct LOINC codes and setting appropriate ranges. This is the recommended approach for standard clinical concepts - use CIEL when available, create custom only when necessary.","fr":"Excellent ! Vous avez utilisé avec succès un concept CIEL. Remarquez que ce concept vient avec plusieurs mappages déjà configurés - à la fois LOINC (718-7) pour l''interopérabilité des laboratoires et l''identifiant CIEL (21). En utilisant des concepts CIEL pour les termes cliniques courants, vous économisez du temps sur la recherche de mappages et bénéficiez de l''expertise de la communauté. L''équipe CIEL a déjà fait le travail de trouver les codes LOINC corrects et de définir des plages appropriées. C''est l''approche recommandée pour les concepts cliniques standard - utilisez CIEL lorsque disponible, créez du personnalisé uniquement lorsque nécessaire."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_9 = LAST_INSERT_ID();


-- ===================================================================
-- EXERCISE 10: Fill-in-Blank - Mapping Relationship Types
-- ===================================================================
VALUES (UUID(), 'FILL_IN_BLANK', '{"instructions":{"en":"Complete the description of mapping relationships.","fr":"Complétez la description des relations de mappage."},"text":{"en":"The {1} relationship should be used whenever a perfect semantic match exists between your concept and the standard term. If your concept is more specific than the standard term, use {2}. Conversely, if your concept is more general than the standard term, use {3}.","fr":"La relation {1} doit être utilisée chaque fois qu''une correspondance sémantique parfaite existe entre votre concept et le terme standard. Si votre concept est plus spécifique que le terme standard, utilisez {2}. Inversement, si votre concept est plus général que le terme standard, utilisez {3}."},"options":[{"en":"SAME-AS","fr":"MÊME-QUE"},{"en":"NARROWER-THAN","fr":"PLUS-ÉTROIT-QUE"},{"en":"BROADER-THAN","fr":"PLUS-LARGE-QUE"},{"en":"ASSOCIATED","fr":"ASSOCIÉ"},{"en":"Q-AND-A","fr":"Q-ET-R"}]}', '{"correctAnswers":{"1":"SAME-AS","2":"NARROWER-THAN","3":"BROADER-THAN"}}', '{"correct":{"en":"Excellent! You understand mapping relationships: SAME-AS for exact matches, NARROWER-THAN when your concept is more specific, BROADER-THAN when your concept is more general.","fr":"Excellent ! Vous comprenez les relations de mappage : MÊME-QUE pour les correspondances exactes, PLUS-ÉTROIT-QUE lorsque votre concept est plus spécifique, PLUS-LARGE-QUE lorsque votre concept est plus général."},"incorrect":{"en":"Review the mapping relationships section. SAME-AS is for exact matches, NARROWER-THAN means your concept is more specific, and BROADER-THAN means your concept is more general.","fr":"Révisez la section des relations de mappage. MÊME-QUE est pour les correspondances exactes, PLUS-ÉTROIT-QUE signifie que votre concept est plus spécifique, et PLUS-LARGE-QUE signifie que votre concept est plus général."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_10 = LAST_INSERT_ID();


